#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-07-20

# =============================================================================
# Deterministic skill-coverage gate — $0, no LLM, no quota, <5 seconds
# =============================================================================
#
# WHY THIS EXISTS
#
# 83 of 114 skills had no automated checks of any kind. test-trigger-keywords.sh
# only covers `user-invocable: true` skills that declare a `triggers:` block,
# which is 31 of them. The LLM eval cannot close that gap either: background
# skills activate by description matching, and skill activation is NOT
# observable in `claude -p` output (the system/init event lists AVAILABLE
# skills; nothing reports which was SELECTED). So for ~76 specs a deterministic
# static gate is the ONLY coverage that can ever exist.
#
# It is also the only gate that keeps working when the subscription's weekly
# cap is exhausted, which is what blocks the paid path in practice.
#
# WHAT IT CHECKS
#   A. description collisions  — two skills competing for the same prompts
#   B. reachability            — skills with no slash command, no model
#                                invocation, and no agent skills: entry
#   C. trigger contradictions  — one prompt claimed should_trigger:true by 2+
#
# RATCHET, NOT A CLIFF
# Pre-existing offenders are recorded in skill-coverage-baseline.json. This
# fails only when a count gets WORSE, so it can land without reddening every
# open PR. Same contract as scripts/eval/route-check.mjs.
# =============================================================================
set -euo pipefail

PROJECT_ROOT="$(cd "$(dirname "${BASH_SOURCE[0]}")/../../.." && pwd)"
BASELINE="$PROJECT_ROOT/tests/skills/triggering/skill-coverage-baseline.json"
cd "$PROJECT_ROOT"

RED=$'\033[0;31m'; GREEN=$'\033[0;32m'; YELLOW=$'\033[1;33m'
BLUE=$'\033[0;34m'; CYAN=$'\033[0;36m'; NC=$'\033[0m'

UPDATE_BASELINE=false
VERBOSE=false
for arg in "$@"; do
  case "$arg" in
    --update-baseline) UPDATE_BASELINE=true ;;
    --verbose) VERBOSE=true ;;
  esac
done

echo "=========================================="
echo "  Skill Coverage Gate (deterministic, \$0)"
echo "=========================================="
echo ""

REPORT=$(python3 - <<'PYEOF'
import json, os, re, glob, collections

SKILLS = "src/skills"
AGENTS = "src/agents"

def frontmatter(path):
    try:
        t = open(path, encoding="utf-8", errors="ignore").read()
    except OSError:
        return "", ""
    m = re.match(r"^---\n(.*?)\n---\n", t, re.S)
    return (m.group(1) if m else ""), t

skills = {}
for d in sorted(glob.glob(f"{SKILLS}/*/")):
    name = os.path.basename(d.rstrip("/"))
    fm, _ = frontmatter(os.path.join(d, "SKILL.md"))
    if not fm:
        continue
    desc = ""
    dm = re.search(r"^description:\s*(.+?)(?=\n[a-z-]+:|\Z)", fm, re.S | re.M)
    if dm:
        desc = " ".join(dm.group(1).split())
    skills[name] = {
        "desc": desc.lower(),
        "user_invocable": bool(re.search(r"^user-invocable:\s*true", fm, re.M)),
        "model_invocable": not bool(
            re.search(r"^disable-model-invocation:\s*true", fm, re.M)),
    }

# Every skill named in any agent's skills: array.
agent_declared = set()
for p in glob.glob(f"{AGENTS}/*.md"):
    fm, _ = frontmatter(p)
    m = re.search(r"^skills:\s*\n((?:\s*-\s*.+\n)+)", fm, re.M)
    if m:
        for line in m.group(1).splitlines():
            s = line.strip().lstrip("-").strip()
            if s:
                agent_declared.add(s)

# ---- A. description collisions -------------------------------------------
# A shared 4-gram only counts when it carries a DOMAIN term. Skill
# descriptions share a lot of template scaffolding ("use when the user"),
# which is noise. A token appearing in <=5 descriptions is domain-specific;
# an n-gram containing one means two skills genuinely compete for a topic.
tokens_by_skill = {n: set(re.findall(r"[a-z][a-z0-9-]{2,}", v["desc"]))
                   for n, v in skills.items()}
df = collections.Counter()
for toks in tokens_by_skill.values():
    df.update(toks)

grams = collections.defaultdict(set)
for name, v in skills.items():
    w = re.findall(r"[a-z][a-z0-9-]{2,}", v["desc"])
    for i in range(max(0, len(w) - 3)):
        grams[" ".join(w[i:i + 4])].add(name)

# Rarity alone still lets template scaffolding through: "use this skill when"
# survives because the literal word "skill" is rare in descriptions, and
# "use when looking for" survives on "looking". Those are structural, not
# topical, so they are excluded by name. A collision must rest on a rare token
# that is actually about the subject matter.
STRUCTURAL = {
    "use", "used", "using", "when", "this", "skill", "skills", "the", "for",
    "and", "with", "that", "should", "looking", "your", "you", "are", "any",
    "its", "their", "from", "into", "over", "via", "per", "not", "but",
    "user", "users", "task", "tasks", "want", "wants", "need", "needs",
}

collisions = []
for g, owners in grams.items():
    if len(owners) < 2:
        continue
    topical = [t for t in g.split() if t not in STRUCTURAL]
    if not topical:
        continue
    rarest = min((df[t] for t in topical), default=99)
    if rarest <= 5:
        collisions.append({"phrase": g, "skills": sorted(owners)})
collisions.sort(key=lambda c: (-len(c["skills"]), c["phrase"]))

# ---- B. reachability ------------------------------------------------------
unreachable = sorted(
    n for n, v in skills.items()
    if not v["user_invocable"] and not v["model_invocable"]
    and n not in agent_declared
)

# ---- C. trigger contradictions -------------------------------------------
claims = collections.defaultdict(set)
for p in glob.glob("tests/evals/skills/*.eval.yaml"):
    sid = os.path.basename(p)[: -len(".eval.yaml")]
    try:
        txt = open(p, encoding="utf-8", errors="ignore").read()
    except OSError:
        continue
    block = re.search(r"^trigger_evals:\s*\n(.*?)(?=^\w|\Z)", txt, re.S | re.M)
    if not block:
        continue
    # pair each prompt with the should_trigger that follows it
    for pm in re.finditer(
            r"-\s*prompt:\s*(\"(?P<q>[^\"]*)\"|(?P<b>[^\n]+))\s*\n\s*should_trigger:\s*(?P<v>true|false)",
            block.group(1)):
        if pm.group("v") != "true":
            continue
        prompt = (pm.group("q") or pm.group("b") or "").strip().strip('"')
        if prompt:
            claims[prompt.lower()].add(sid)
contradictions = sorted(
    ({"prompt": k, "skills": sorted(v)} for k, v in claims.items() if len(v) > 1),
    key=lambda c: c["prompt"])

print(json.dumps({
    "total_skills": len(skills),
    "collisions": collisions,
    "unreachable": unreachable,
    "contradictions": contradictions,
}))
PYEOF
)

n_skills=$(echo "$REPORT" | jq -r '.total_skills')
n_col=$(echo "$REPORT" | jq -r '.collisions | length')
n_unreach=$(echo "$REPORT" | jq -r '.unreachable | length')
n_contra=$(echo "$REPORT" | jq -r '.contradictions | length')

echo "  Skills scanned: ${n_skills}"
echo ""
printf '  %-28s %s\n' "description collisions" "$n_col"
printf '  %-28s %s\n' "unreachable skills"     "$n_unreach"
printf '  %-28s %s\n' "trigger contradictions" "$n_contra"
echo ""

if [[ "$n_col" -gt 0 ]]; then
  echo "${BLUE}--- description collisions (two skills competing) ---${NC}"
  echo "$REPORT" | jq -r '.collisions[] | "  \(.skills | join("  vs  "))\n      \"\(.phrase)\""' | head -40
  echo ""
fi
if [[ "$n_unreach" -gt 0 ]]; then
  echo "${BLUE}--- unreachable: no slash command, no model invocation, no agent ---${NC}"
  echo "$REPORT" | jq -r '.unreachable[] | "  \(.)"'
  echo ""
fi
if [[ "$n_contra" -gt 0 ]]; then
  echo "${BLUE}--- one prompt claimed should_trigger:true by 2+ skills ---${NC}"
  echo "$REPORT" | jq -r '.contradictions[] | "  \(.skills | join(", "))\n      \"\(.prompt)\""' | head -20
  echo ""
fi

$VERBOSE && echo "$REPORT" | jq .

if $UPDATE_BASELINE; then
  jq -n --argjson c "$n_col" --argjson u "$n_unreach" --argjson x "$n_contra" \
    '{schema:"ork-skill-coverage-baseline/1.0",
      description:"Ratchet floor for the deterministic skill-coverage gate. Counts may only go DOWN. Regenerate with --update-baseline when an offender is genuinely fixed.",
      collisions:$c, unreachable:$u, contradictions:$x}' > "$BASELINE"
  echo "${GREEN}Baseline written:${NC} $BASELINE"
  exit 0
fi

if [[ ! -f "$BASELINE" ]]; then
  echo "${YELLOW}No baseline on disk — writing it from the current counts.${NC}"
  echo "${YELLOW}This run passes; future runs fail if any count increases.${NC}"
  jq -n --argjson c "$n_col" --argjson u "$n_unreach" --argjson x "$n_contra" \
    '{schema:"ork-skill-coverage-baseline/1.0",
      description:"Ratchet floor for the deterministic skill-coverage gate. Counts may only go DOWN.",
      collisions:$c, unreachable:$u, contradictions:$x}' > "$BASELINE"
  exit 0
fi

b_col=$(jq -r '.collisions' "$BASELINE")
b_unreach=$(jq -r '.unreachable' "$BASELINE")
b_contra=$(jq -r '.contradictions' "$BASELINE")

echo "=========================================="
echo "  Ratchet"
echo "=========================================="
fail=0
check() {
  local label="$1" now="$2" base="$3"
  if [[ "$now" -gt "$base" ]]; then
    printf '  %s%-24s %s > %s (baseline) REGRESSION%s\n' "$RED" "$label" "$now" "$base" "$NC"
    fail=1
  elif [[ "$now" -lt "$base" ]]; then
    printf '  %s%-24s %s < %s — improved, run --update-baseline%s\n' "$GREEN" "$label" "$now" "$base" "$NC"
  else
    printf '  %s%-24s %s (at baseline)%s\n' "$CYAN" "$label" "$now" "$NC"
  fi
}
check "collisions"     "$n_col"     "$b_col"
check "unreachable"    "$n_unreach" "$b_unreach"
check "contradictions" "$n_contra"  "$b_contra"
echo ""

if [[ "$fail" -eq 1 ]]; then
  echo "${RED}FAIL: a skill-coverage count regressed against the baseline.${NC}"
  exit 1
fi
echo "${GREEN}PASS: no skill-coverage regression.${NC}"
